type TodoList = Vec<String>;

fn load_or_create_empty(path: &str) -> io::Result<TodoList> {
    match fs::read_to_string(path) {
        Ok(s) => {
            let todos: TodoList = serde_json::from_str(&s)
                .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;
            Ok(todos)
        }
        Err(e) if e.kind() == io::ErrorKind::NotFound => Ok(Vec::new()),
        Err(e) => Err(e),
    }
