  "main.rs": "use anyhow::Result;
use async_trait::async_trait;
use std::path::{Path, PathBuf};
use tokio::time::{sleep, Duration};

// async fn in traits is not (currently) object-safe by default.
// async-trait rewrites each async method into a dyn-compatible method
// returning a boxed Future.
#[async_trait]
pub trait RemoteActions: Send {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()>;
    async fn remove_repo(&mut self, path: &Path) -> Result<()>;
    async fn add_repo(&mut self, path: &Path) -> Result<()>;

    fn get_element(&self, num: usize) -> Result<String>;
}

struct NoopActions;

#[async_trait]
impl RemoteActions for NoopActions {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()> {
        println!("[noop] change_path: {} -> {}", from.display(), to.display());
        Ok(())
    }

    async fn remove_repo(&mut self, path: &Path) -> Result<()> {
        println!("[noop] remove_repo: {}", path.display());
        Ok(())
    }

    async fn add_repo(&mut self, path: &Path) -> Result<()> {
        println!("[noop] add_repo: {}", path.display());
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        Ok(format!("[noop] element-{num}"))
    }
}

struct ProdActions {
    base: PathBuf,
}

#[async_trait]
impl RemoteActions for ProdActions {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()> {
        // pretend this does real network work
        println!("[prod] change_path: {} -> {}", from.display(), to.display());
        sleep(Duration::from_millis(50)).await;
        Ok(())
    }

    async fn remove_repo(&mut self, path: &Path) -> Result<()> {
        println!("[prod] remove_repo: {}", path.display());
        sleep(Duration::from_millis(50)).await;
        Ok(())
    }

    async fn add_repo(&mut self, path: &Path) -> Result<()> {
        println!("[prod] add_repo: {}", path.display());
        sleep(Duration::from_millis(50)).await;
        Ok(())
    }

    fn get_element(&self, num: usize) -> Result<String> {
        Ok(format!("[prod] {}/element-{num}", self.base.display()))
    }
}

async fn run(actions: &mut dyn RemoteActions) -> Result<()> {
    let from = Path::new("/tmp/repoA");
    let to = Path::new("/mnt/host/repoA");

    actions.add_repo(from).await?;
    actions.change_path(from, to).await?;
    actions.remove_repo(to).await?;

    println!("get_element(3) => {}", actions.get_element(3)?);
    Ok(())
}

#[tokio::main]
async fn main() -> Result<()> {
    let use_noop = true;

    let mut actions: Box<dyn RemoteActions> = if use_noop {
        Box::new(NoopActions)
    } else {
        Box::new(ProdActions {
            base: PathBuf::from("/srv"),
        })
    };

    run(actions.as_mut()).await?;
    Ok(())
}
"
