[dependencies]
tempfile = "3"
",
  "main.rs": "use std::io::Write;
use std::process::{Command, ExitStatus};

/// This is the packaged Python script.
///
/// In a real project you can put it at (for example) `src/python/script.py`
/// and embed it like:
///
///     const PY_SCRIPT: &str = include_str!("python/script.py");
///
/// For this self-contained example (no extra files), we embed it directly.
const PY_SCRIPT: &str = r#"""
import sys

def main():
    print("Hello from embedded script.py")
    print("argv:", sys.argv)

if __name__ == "__main__":
    main()
"""#;

fn find_python() -> Result<String, String> {
    // Prefer python3 when available, otherwise fall back to python.
    for candidate in ["python3", "python"] {
        match Command::new(candidate).arg("--version").output() {
            Ok(out) if out.status.success() => return Ok(candidate.to_string()),
            Ok(_) => continue,
            Err(_) => continue,
        }
    }
    Err("Could not find a working Python interpreter (tried: python3, python)".to_string())
}

fn run_python_script(script_contents: &str, script_args: &[String]) -> Result<ExitStatus, String> {
    let python = find_python()?;

    // Write the packaged script to a temp file and execute it by filesystem path.
    // (This satisfies the "what path to pass to python" requirement.)
    let mut f = tempfile::NamedTempFile::new().map_err(|e| e.to_string())?;
    f.write_all(script_contents.as_bytes())
        .map_err(|e| e.to_string())?;
    f.flush().map_err(|e| e.to_string())?;

    let script_path = f.path().to_path_buf();

    // Forward any CLI args passed to the Rust program into the Python script.
    let status = Command::new(&python)
        .arg(&script_path)
        .args(script_args)
        .status()
        .map_err(|e| format!("Failed to spawn {python}: {e}"))?;

    // Keep `f` alive until after the process completes so the temp file still exists.
    drop(f);

    Ok(status)
}

fn main() {
    let args: Vec<String> = std::env::args().skip(1).collect();

    match run_python_script(PY_SCRIPT, &args) {
        Ok(status) => {
            // Propagate exit code.
            std::process::exit(status.code().unwrap_or(1));
        }
        Err(msg) => {
            eprintln!("{msg}");
            std::process::exit(1);
        }
    }
}
"
}
