  "Cargo.toml": "[package]
name = "shell_tokenize"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "use std::io::{self, Read};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TokenizeError {
    UnclosedSingleQuote,
}

/// Split a command line into tokens like a (very small) subset of bash:
/// - ASCII whitespace separates tokens
/// - single quotes preserve everything inside and are removed
/// - quoted and unquoted parts can be concatenated into one token
///
/// Examples:
///   one  ' two  'three    four  -> ["one", " two  three", "four"]
///   ''                           -> [""]
fn tokenize(input: &str) -> Result<Vec<String>, TokenizeError> {
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    enum State {
        Unquoted,
        SingleQuoted,
    }

    let mut out: Vec<String> = Vec::new();
    let mut cur = String::new();
    let mut started = false; // distinguishes "no token in progress" from "empty token" (e.g. '')
    let mut state = State::Unquoted;

    for ch in input.chars() {
        match state {
            State::Unquoted => match ch {
                '\'' => {
                    state = State::SingleQuoted;
                    started = true;
                }
                _ if ch.is_ascii_whitespace() => {
                    if started {
                        out.push(std::mem::take(&mut cur));
                        started = false;
                    }
                }
                _ => {
                    cur.push(ch);
                    started = true;
                }
            },
            State::SingleQuoted => {
                if ch == '\'' {
                    state = State::Unquoted;
                } else {
                    cur.push(ch);
                    // started is already true when we entered quotes, but keeping this is harmless.
                    started = true;
                }
            }
        }
    }

    if state == State::SingleQuoted {
        return Err(TokenizeError::UnclosedSingleQuote);
    }

    if started {
        out.push(cur);
    }

    Ok(out)
}

fn main() {
    // If stdin has content, tokenize that; otherwise use a built-in example.
    let mut buf = String::new();
    let _ = io::stdin().read_to_string(&mut buf);
    let input = buf.trim_end_matches(['\n', '\r']);

    let input = if input.is_empty() {
        " one  ' two  'three    four"
    } else {
        input
    };

    match tokenize(input) {
        Ok(tokens) => {
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("tokenize error: {:?}", e);
            std::process::exit(2);
        }
    }
}
"
}

