    // - fragment (after '#') is treated as a JSON Pointer (RFC 6901)
    let (file_part, frag_part) = match ref_str.split_once('#') {
        Some((f, frag)) => (f, frag),
        None => (ref_str, ""),
    };

    if file_part.is_empty() {
        bail!("empty file part in $ref is not supported in this demo: {ref_str}");
    }

    let file_path = base_dir.join(file_part);
    let file_dir = file_path.parent().unwrap_or_else(|| Path::new("."));

    let text = fs::read_to_string(&file_path)
        .with_context(|| format!("failed to read referenced file: {}", file_path.display()))?;
    let doc: Value = serde_json::from_str(&text)
        .with_context(|| format!("failed to parse referenced file as JSON: {}", file_path.display()))?;

    let target = if frag_part.is_empty() {
        doc
    } else {
        // In refs like "./a.json#/p_list", frag_part is "/p_list".
        // We require a JSON pointer-style fragment.
        if !frag_part.starts_with('/') {
            bail!(
                "unsupported fragment in $ref (expected JSON Pointer starting with '/'): #{frag_part}"
            );
        }

        doc.pointer(frag_part)
            .cloned()
            .ok_or_else(|| anyhow!("$ref JSON pointer not found: {}#{}", file_part, frag_part))?
    };

    // Recurse: referenced content might itself contain $ref.
    resolve_refs(target, file_dir)
}
