    /// Safe, no copies of `elems` or `B`s: computes each (i,j) pair once (i<j)
    /// and updates neighbor lists for both i and j.
    pub fn build_lists_pairwise_sequential(&mut self) {
        let n = self.elems.len();
        for e in &mut self.elems {
            e.nb.clear();
        }

        for i in 0..n {
            for j in (i + 1)..n {
