use std::thread;

/// Replacement for `AtomicUsize::fetch_add(val, Ordering::Relaxed)`
/// using a critical section.
///
/// Ordering choice:
/// - If all accesses to the counter are done inside the same critical section,
///   there is no interleaving of operations, so the atomic *ordering* is not
///   providing synchronization; mutual exclusion is.
/// - To match the original code (`fetch_add(..., Relaxed)`), `Relaxed` is the
///   correct ordering for the internal `load`/`store`.
///
/// Important: if *any* other code modifies the same atomic concurrently *without*
/// the same critical section, this load+store sequence is not an atomic RMW and
/// can lose updates.
fn fetch_add_cs(a: &AtomicUsize, val: usize) -> usize {
    critical_section::with(|_| {
        let old = a.load(Ordering::Relaxed);
        // `fetch_add` is defined to wrap on overflow.
        a.store(old.wrapping_add(val), Ordering::Relaxed);
        old
    })
}

fn main() {
    // This example runs on the host with `critical-section`'s `std` feature,
    // which implements critical sections with a global lock.
    // On embedded (e.g. rp2040), the platform implementation typically disables
    // interrupts and/or uses a hardware spinlock.

    let counter = Arc::new(AtomicUsize::new(0));

    let threads = 8;
    let iters = 100_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c = counter.clone();
        handles.push(thread::spawn(move || {
            for _ in 0..iters {
                let _prev = fetch_add_cs(&c, 1);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let expected = threads * iters;
    let got = counter.load(Ordering::Relaxed);
    println!("expected={expected} got={got}");
}
"
}
