/// Iterates all cartesian indices for an N-D shape in row-major order.
#[derive(Debug, Clone)]
struct IndicesIter {
    dims: Vec<usize>,
    cur: Vec<usize>,
    done: bool,
}

impl IndicesIter {
    fn new(dims: Vec<usize>) -> Self {
        let nd = dims.len();
        let empty = dims.iter().any(|&d| d == 0);
        Self {
            dims,
            cur: vec![0; nd],
            done: empty,
        }
    }
}

impl Iterator for IndicesIter {
    type Item = Vec<usize>;

    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }
        let out = self.cur.clone();

        // increment like an odometer, last axis fastest.
        for axis in (0..self.dims.len()).rev() {
            self.cur[axis] += 1;
            if self.cur[axis] < self.dims[axis] {
                return Some(out);
            }
            self.cur[axis] = 0;
        }
        // overflow => done
        self.done = true;
        Some(out)
    }
}

/// Immutable iterator can be a normal `Iterator<Item = &'a T>`.
#[derive(Debug)]
pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    indices: IndicesIter,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = self.indices.next()?;
        let v: &'a T = &self.array[&idx[..]];
        Some((idx, v))
    }
