/// `Iterator<Item = &'a mut T>` safely: each `next(&mut self)` creates a
/// mutable borrow of `self`, so the reference you return must be tied to that
/// borrow (it cannot outlive the call).
///
/// The standard solution is a "streaming" iterator: the yielded reference is
/// borrowed from `&mut self` with a lifetime chosen by the caller.
pub trait StreamingIterator {
    type Item<'s>
    where
        Self: 's;

    fn next(&mut self) -> Option<Self::Item<'_>>;
}

#[derive(Debug)]
pub struct ArrayIterMut<'a, T> {
    array: &'a mut Array<T>,
    indices: IndicesIter,
}

impl<T> StreamingIterator for ArrayIterMut<'_, T> {
    type Item<'s> = (Vec<usize>, &'s mut T) where Self: 's;

    fn next(&mut self) -> Option<Self::Item<'_>> {
        let idx = self.indices.next()?;
        // The returned `&mut T` is valid only as long as the borrow of `&mut self`.
        let v: &mut T = &mut self.array[&idx[..]];
        Some((idx, v))
    }
}

fn main() {
    // 2x3 array
    let mut a = Array::from_vec(vec![2, 3], vec![1, 2, 3, 4, 5, 6]);

    println!("Immutable iteration:");
    for (idx, v) in a.iter_indexed() {
        println!("  {:?} -> {}", idx, v);
    }

    println!("\nMutable streaming iteration (in-place add 10):");
    {
        let mut it = a.iter_indexed_mut_streaming();
        while let Some((idx, v)) = it.next() {
            *v += 10;
            println!("  updated {:?}", idx);
        }
    }

    println!("\nAfter mutation:");
    for (idx, v) in a.iter_indexed() {
        println!("  {:?} -> {}", idx, v);
    }

    // Note: With the streaming iterator, you cannot keep two yielded `&mut T`
    // alive at the same time (that would require aliasing mutable references).
}
"
}
