/// One step of SplitMix64.
///
/// Returns (next_state, output).
const fn splitmix64_step(state: u64) -> (u64, u64) {
    let next_state = state.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = next_state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    z ^= z >> 31;
    (next_state, z)
}

const fn generate_zobrist_seeds() -> [u64; N] {
    let mut result = [0u64; N];
    let mut state = SEED;

    let mut i = 0;
    while i < N {
        let (next_state, value) = splitmix64_step(state);
        state = next_state;
        result[i] = value;
        i += 1;
    }

    result
}

